319	func (p *preClaimReadinessWaiversPayload) UnmarshalJSON(data []byte) error {
320		trimmed := strings.TrimSpace(string(data))
321		if trimmed == "" || trimmed == "null" {
322			return nil
323		}
324		if trimmed[0] == '"' {
325			var reason string
326			if err := json.Unmarshal(data, &reason); err != nil {
327				return err
328			}
329			reason = strings.TrimSpace(reason)
330			if reason == "" {
331				return nil
332			}
333			*p = []preClaimReadinessWaiver{{Reason: reason}}
334			return nil
335		}
336		if trimmed[0] != '[' {
337			return fmt.Errorf("waivers_applied must be a JSON array or string")
338		}
339		var raw []json.RawMessage
340		if err := json.Unmarshal(data, &raw); err != nil {
341			return err
342		}
343		waivers := make([]preClaimReadinessWaiver, 0, len(raw))
344		for _, item := range raw {
345			itemTrimmed := strings.TrimSpace(string(item))
346			if itemTrimmed == "" || itemTrimmed == "null" {
347				continue
348			}
349			switch itemTrimmed[0] {
350			case '"':
351				var reason string
352				if err := json.Unmarshal(item, &reason); err != nil {
353					return err
354				}
355				reason = strings.TrimSpace(reason)
356				if reason == "" {
357					continue
358				}
359				waivers = append(waivers, preClaimReadinessWaiver{Reason: reason})
360			case '{':
361				var waiver preClaimReadinessWaiver
362				if err := json.Unmarshal(item, &waiver); err != nil {
363					return err
364				}
365				waiver.Reason = strings.TrimSpace(waiver.Reason)
366				waiver.Criteria = normalizeReadinessStringList(waiver.Criteria)
367				waiver.Evidence = strings.TrimSpace(waiver.Evidence)
368				waivers = append(waivers, waiver)
369			default:
370				return fmt.Errorf("waivers_applied entries must be strings or objects")
371			}
372		}
373		*p = waivers
374		return nil
375	}
