549	func applyLifecycleHookRouting(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime *AgentRunRuntime, selector func(ProfileSnapshot) string) {
550		runtime.ClearRoutingPins = true
551	
552		pinned := false
553		if harness, ok := rcfg.ExplicitHarness(); ok {
554			runtime.HarnessOverride = strings.TrimSpace(harness)
555			pinned = true
556		}
557		if provider, ok := rcfg.ExplicitProvider(); ok {
558			runtime.ProviderOverride = strings.TrimSpace(provider)
559			pinned = true
560		}
561		if model, ok := rcfg.ExplicitModel(); ok {
562			runtime.ModelOverride = strings.TrimSpace(model)
563			pinned = true
564		}
565		if pinned {
566			return
567		}
568		runtime.ProfileOverride = selectProfileForDispatch(ctx, projectRoot, svc, runner, selector)
569	}
