575	func preClaimIntakeRouteUnavailableDetail(err error) string {
576		detail := ""
577		if err != nil {
578			detail = strings.TrimSpace(err.Error())
579		}
580		detail = trimDiagnosticPrefix(detail, "pre-claim intake")
581		detail = strings.TrimPrefix(strings.TrimSpace(detail), "dispatch: ")
582		if detail == "" {
583			return "readiness route unavailable"
584		}
585		return "readiness route unavailable: " + detail
586	}
