588	func dispatchPreClaimIntakePayloadOnce(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (string, error) {
589		result, err := dispatchLifecycleRun(ctx, projectRoot, svc, runner, rcfg, runtime)
590		if err != nil {
591			return "", fmt.Errorf("pre-claim intake: dispatch: %w", err)
592		}
593		return intakeResultPayload(result)
594	}
